// Formatte les résultats selon le type spécifié
const allResults = $input.all();
const userQuestion = $('Webhook').first().json.body.chatInput;
const sessionId = $('Webhook').first().json.body.sessionId;

// Récupère les métadonnées
const metadata = allResults[0]?.json?._metadata || {};
const formatType = metadata.format || 'list';
const stats = metadata.stats;
const resultCount = allResults.length;

if (resultCount === 0) {
  return [{
    json: {
      formattedResponse: `Désolé, je n'ai trouvé aucune donnée correspondant à votre requête : "${userQuestion}".`,
      sessionId: sessionId,
      format: 'text',
      resultCount: 0
    }
  }];
}

let rawData = allResults.map(item => item.json);

// Correction : transmettre le JSON natif pour chart/advanced_chart, et sécuriser l'accès aux propriétés
if (formatType === 'chart' || formatType === 'advanced_chart') {
  return [{
    json: {
      formattedResponse: '[GRAPH_DATA]',
      sessionId: sessionId,
      format: formatType,
      resultCount: resultCount,
      rawResults: rawData,
      metadata: metadata,
      chart_metadata: metadata.chart_metadata || null
    }
  }];
}

let response = '';

switch(formatType) {
  case 'simple':
    if (allResults[0] && allResults[0].json) {
      const value = Object.values(allResults[0].json)[0];
      response = `**Résultat :** ${value}`;
    }
    break;

  case 'list':
    response = `**Résultats (${resultCount}) :**\n\n`;
    allResults.forEach((item, index) => {
      const data = item.json || {};
      const columns = Object.keys(data);
      if (columns.length === 1) {
        response += `• ${data[columns[0]]}\n`;
      } else {
        const values = columns.map(col => `${data[col]}`).join(' - ');
        response += `${index + 1}. ${values}\n`;
      }
    });
    break;

  case 'table':
    if (allResults[0] && allResults[0].json) {
      const columns = Object.keys(allResults[0].json);
      response = `**Tableau des résultats (${resultCount} lignes) :**\n\n`;
      response += '| ' + columns.join(' | ') + ' |\n';
      response += '|' + columns.map(() => '---').join('|') + '|\n';
      allResults.forEach(item => {
        const row = columns.map(col => item.json[col] || '').join(' | ');
        response += `| ${row} |\n`;
      });
    }
    break;

  case 'stats':
    response = `**Statistiques :**\n\n`;
    response += `Total : ${resultCount} enregistrement(s)\n\n`;
    if (stats) {
      Object.keys(stats).forEach(col => {
        const s = stats[col];
        response += `**${col} :**\n`;
        response += `  • Somme : ${s.sum.toFixed(2)}\n`;
        response += `  • Moyenne : ${s.avg.toFixed(2)}\n`;
        response += `  • Min : ${s.min.toFixed(2)}\n`;
        response += `  • Max : ${s.max.toFixed(2)}\n\n`;
      });
    }
    if (resultCount <= 20) {
      response += `**Détails :**\n`;
      allResults.forEach((item, index) => {
        const data = item.json || {};
        const values = Object.entries(data).map(([key, value]) => `${key}: ${value}`).join(', ');
        response += `${index + 1}. ${values}\n`;
      });
    }
    break;

  default:
    response = `**Résultats pour :** ${userQuestion}\n\n`;
    allResults.forEach((item, index) => {
      const data = item.json || {};
      const values = Object.entries(data).map(([key, value]) => `**${key}** : ${value}`).join(', ');
      response += `${index + 1}. ${values}\n`;
    });
}

response += `\n---\n*${resultCount} résultat(s) trouvé(s)*`;

return [{
  json: {
    formattedResponse: response,
    sessionId: sessionId,
    format: formatType,
    resultCount: resultCount,
    rawResults: rawData,
    metadata: metadata
  }
}];

// Analyse le type de données et détermine le format optimal
const sqlQuery = $('Edit Fields5').first().json.sql[0];
const aiResponse = $('AI Agent de Classification1').first().json.output;
const queryResults = $input.all();
const userQuestion = $('Webhook').first().json.body.chatInput;

// Récupère le format depuis la réponse de l'agent
let format = $('Edit Fields5').first().json.format || 'auto';

// Correction : priorité absolue aux formats chart/advanced_chart si détectés dans la réponse AI
if (aiResponse.format === 'chart' || aiResponse.format === 'advanced_chart') {
  format = aiResponse.format;
}

// Détection automatique si 'auto' (mais ne jamais écraser chart/advanced_chart)
if (format === 'auto') {
  const results = queryResults[0]?.json || {};
  const columns = Object.keys(results);
  const rowCount = queryResults.length;

  if (rowCount === 1 && columns.length === 1) {
    format = 'simple';
  } else if (columns.includes('count') || columns.includes('total') || columns.includes('sum') || columns.includes('avg')) {
    format = 'stats';
  } else if (rowCount <= 10 && columns.length <= 4) {
    format = 'list';
  } else if (rowCount > 10 || columns.length > 4) {
    format = 'table';
  } else {
    format = 'list';
  }
}

// Analyse les données pour les statistiques
let stats = null;
if (format === 'stats' || format === 'chart' || format === 'advanced_chart') {
  const numericColumns = {};
  queryResults.forEach(item => {
    const data = item.json || {};
    Object.keys(data).forEach(key => {
      if (!isNaN(parseFloat(data[key])) && data[key] !== null) {
        if (!numericColumns[key]) numericColumns[key] = [];
        numericColumns[key].push(parseFloat(data[key]));
      }
    });
  });

  if (Object.keys(numericColumns).length > 0) {
    stats = {};
    Object.keys(numericColumns).forEach(col => {
      const values = numericColumns[col];
      stats[col] = {
        sum: values.reduce((a, b) => a + b, 0),
        avg: values.reduce((a, b) => a + b, 0) / values.length,
        min: Math.min(...values),
        max: Math.max(...values),
        count: values.length
      };
    });
  }
}

return queryResults.map(item => ({
  ...item,
  json: {
    ...item.json,
    _metadata: {
      format: format,
      stats: stats,
      userQuestion: userQuestion,
      query: sqlQuery,
      resultCount: queryResults.length,
      columnCount: Object.keys(item.json || {}).length
    }
  }
}));

// Gère les erreurs de requête SQL
const error = $('SaaS GESTOCKPRO').first().json.error;
const userQuestion = $('Webhook').first().json.body.chatInput;
const sessionId = $('Webhook').first().json.body.sessionId;

let errorMessage = "Une erreur est survenue lors de l'exécution de la requête SQL.";

if (error && error.message) {
  if (error.message.includes("syntax error")) {
    errorMessage = "Désolé, il y a une erreur de syntaxe dans la requête SQL générée. Veuillez reformuler votre question.";
  } else if (error.message.includes("tenant_id")) {
    errorMessage = "Erreur d'accès aux données. Vérifiez que vous avez les bonnes autorisations.";
  } else if (error.message.includes("does not exist")) {
    errorMessage = "La table ou colonne demandée n'existe pas dans la base de données.";
  }
}

return [{
  json: {
    formattedResponse: `❌ ${errorMessage}\n\n**Question :** ${userQuestion}\n\nVeuillez reformuler votre demande ou contacter le support si le problème persiste.`,
    sessionId: sessionId,
    format: 'error',
    resultCount: 0
  }
}];
